import React, { useState } from "react";
import axios from "axios";

function AudioUpload() {
  const [audioFile, setAudioFile] = useState(null);

  // Function to handle file input change
  const handleFileChange = (e) => {
    setAudioFile(e.target.files[0]);
  };

  // Function to handle the file upload
  const handleUpload = async () => {
    if (!audioFile) {
      alert("Please select an audio file.");
      return;
    }

    const formData = new FormData();
    formData.append("audio", audioFile); // Add the audio file to FormData

    try {
      const response = await axios.post("http://localhost:5001/upload", formData, {
        headers: {
          "Content-Type": "multipart/form-data", // Ensure the correct content type is set
        },
      });

      console.log("Server response:", response.data); // Log the response from the server

      // Check the response message and alert accordingly
      if (response.data.message === "Audio file uploaded successfully!") {
        alert("Audio uploaded successfully!");
      } else {
        alert("Failed to upload audio.");
      }
    } catch (error) {
      console.error("Error uploading file:", error.response?.data || error.message);
      alert("Failed to upload audio.");
    }
  };

  return (
    <div>
      <h1>Upload Audio File</h1>
      <input type="file" onChange={handleFileChange} accept="audio/*" />
      <button onClick={handleUpload}>Upload</button>
    </div>
  );
}

export default AudioUpload;
